args.command:
\
cat task.json && \
echo "---" && \
node -e "
const schema = require('./schema.json');
const task = require('./task.json');
const Ajv = require('ajv');
const ajv = new Ajv();
const validate = ajv.compile(schema);
const valid = validate(task);
if (!valid) {
  console.log('VALIDATION FAILED:');
  console.log(validate.errors);
  process.exit(1);
} else {
  console.log('✓ Validates against schema');
  console.log('✓ Exactly 3 keys present:', Object.keys(task).sort().join(', '));
  console.log('✓ No tags field:', !task.tags);
  console.log('✓ No assignee field:', !task.assignee);
}
"
